fixed_code:
trait Div { fn divide(self, rhs: i32) -> Result<i32, &'static str>; }

impl Div for i32 {
    fn divide(self, rhs: i32) -> Result<i32, &'static str> {
        if rhs == 0 {
            Err("division by zero")
        } else {
            Ok(self / rhs)
        }
    }
}

fn main() {
    let x = 10;
    let y = 0;
    match x.divide(y) {
        Ok(result) => println!("{} divided by {} is {}
", x, y, result),
        Err(e) => eprintln!("Error: {}
", e)
    }
}
